// Extract email data and split PDF attachments into separate items for loop processing
const item = $input.first();
const emailData = item.json;
const binary = item.binary || {};

// Extract email fields
const subject = emailData.subject || '';
const bodyText = (emailData.textPlain || emailData.text || emailData.html || '').substring(0, 5000);
const fromRaw = emailData.from || '';
// Extract email address from 'Name <user@example.com>' format
const emailMatch = fromRaw.match(/<([^>]+)>/);
const senderEmail = emailMatch ? emailMatch[1] : fromRaw;
const senderName = fromRaw.replace(/<[^>]+>/, '').trim();

// Combine subject + body as the request text
const requestText = subject + (bodyText ? '\n\n' + bodyText : '');

// Scan binary attachments for PDFs
const pdfItems = [];
for (const key of Object.keys(binary)) {
  const bin = binary[key];
  if (bin.mimeType === 'application/pdf' || (bin.fileName && bin.fileName.toLowerCase().endsWith('.pdf'))) {
    pdfItems.push({ fileName: bin.fileName || `document-${pdfItems.length + 1}.pdf`, binaryKey: key });
  }
}

if (pdfItems.length === 0) {
  return [{ json: { requestText, senderEmail, senderName, hasPdfs: false, pdfCount: 0 } }];
}

// Output one item per PDF with its binary under the key 'data'
const results = [];
for (let i = 0; i < pdfItems.length; i++) {
  const pdf = pdfItems[i];
  results.push({
    json: { requestText, senderEmail, senderName, hasPdfs: true, pdfCount: pdfItems.length, pdfIndex: i, pdfFileName: pdf.fileName, pdfBinaryKey: 'data' },
    binary: { data: binary[pdf.binaryKey] }
  });
}
return results;

const item = $input.first();
const status = item.json.status;
const loopItem = $('Loop Over PDFs').first().json;
const fileName = loopItem.pdfFileName || 'document.pdf';

let ocrText = '';
if (status === 'COMPLETED') {
  ocrText = item.json.result?.markdown || item.json.result?.text || item.json.metadata?.markdown || item.json.metadata?.text || JSON.stringify(item.json.result || item.json.metadata || {});
  ocrText = ocrText.substring(0, 15000);
} else if (status === 'FAILED') {
  ocrText = '[OCR failed — could not process this PDF]';
} else {
  ocrText = '[OCR still processing — try increasing wait time]';
}

return [{
  json: {
    pdfFileName: fileName,
    ocrText
  }
}];

// Collect all OCR results from the loop and combine with original request
const allItems = $('Extract OCR Text').all();
const formData = $('Extract & Split PDFs').first().json;

const pdfSections = allItems.map((item, i) => {
  const name = item.json.pdfFileName || `Document ${i + 1}`;
  return `### PDF ${i + 1}: ${name}\n\n${item.json.ocrText}`;
}).join('\n\n---\n\n');

return [{
  json: {
    requestText: formData.requestText,
    senderEmail: formData.senderEmail,
    pdfContent: pdfSections,
    pdfCount: allItems.length,
    hasPdfs: true
  }
}];

const formData = $input.first().json;

return [{
  json: {
    requestText: formData.requestText,
    senderEmail: formData.senderEmail,
    pdfContent: '',
    pdfCount: 0,
    hasPdfs: false
  }
}];

// Merge the context data with the downloaded markdown syntax
const syntaxData = $input.first().json?.data || '';

// Get the context from whichever branch was executed
let context;
try {
  context = $('Combine All OCR Results').first().json;
} catch (e) {
  try {
    context = $('Prepare Text Only').first().json;
  } catch (e2) {
    context = $('Extract & Split PDFs').first().json;
  }
}

return [{
  json: {
    ...context,
    markdownSyntax: syntaxData.substring(0, 12000)
  }
}];

const agentOutput = $json.output || $json.text || '';
const config = $('Set Company Config').first().json;
const context = $('Merge Context').first().json;

// Clean markdown: remove code fences if the AI wrapped it
let markdown = agentOutput;
if (markdown.startsWith('```')) {
  markdown = markdown.replace(/^```(?:markdown|md)?\n?/, '').replace(/\n?```$/, '');
}
markdown = markdown.trim();

// Build a clean filename
const requestText = context.requestText || 'document';
const cleanName = requestText
  .substring(0, 60)
  .replace(/[^a-zA-Z0-9\s-]/g, '')
  .replace(/\s+/g, '-')
  .toLowerCase();

const today = new Date().toISOString().split('T')[0];

return [{
  json: {
    markdown,
    filename: `${cleanName}-${today}`,
    title: requestText.substring(0, 100),
    senderEmail: context.senderEmail,
    companyName: config.companyName,
    companyLogoUrl: config.companyLogoUrl,
    brandColor: config.brandColor
  }
}];
